"use client";

import { use } from "react";
import { users, currentUser } from "@/lib/data";
import ProfileHeader from "@/components/profile/ProfileHeader";
import SkillBadges from "@/components/profile/SkillBadges";
import Portfolio from "@/components/profile/Portfolio";
import Availability from "@/components/profile/Availability";
import Button from "@/components/ui/Button";
import { Settings } from "lucide-react";
import Link from "next/link";
import { notFound } from "next/navigation";

export default function ProfilePage({
  params,
}: {
  params: Promise<{ username: string }>;
}) {
  const { username } = use(params);
  const user = users.find((u) => u.username === username);

  if (!user) {
    notFound();
  }

  const isOwnProfile = user.id === currentUser.id;

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
      {/* Edit button for own profile */}
      {isOwnProfile && (
        <div className="flex justify-end">
          <Link href="/profile/edit">
            <Button variant="outline" size="sm" icon={<Settings className="w-4 h-4" />}>
              Edit Profile
            </Button>
          </Link>
        </div>
      )}

      <ProfileHeader user={user} isOwnProfile={isOwnProfile} />
      <SkillBadges
        skillsTeach={user.skillsTeach}
        skillsLearn={user.skillsLearn}
      />
      <Portfolio items={user.portfolio} />
      <Availability availability={user.availability} />
    </div>
  );
}
